129	/**
130	 * Create a fal.ai provider instance.
131	 */
132	export function createFal(options: FalProviderSettings = {}): FalProvider {
133	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
134	  const getHeaders = () =>
135	    withUserAgentSuffix(
136	      {
137	        Authorization: `Key ${loadFalApiKey({
138	          apiKey: options.apiKey,
139	        })}`,
140	        ...options.headers,
141	      },
142	      `ai-sdk/fal/${VERSION}`,
143	    );
144	
145	  const createImageModel = (modelId: FalImageModelId) =>
146	    new FalImageModel(modelId, {
147	      provider: 'fal.image',
148	      baseURL: baseURL ?? defaultBaseURL,
149	      headers: getHeaders,
150	      fetch: options.fetch,
151	    });
152	
153	  const createSpeechModel = (modelId: FalSpeechModelId) =>
154	    new FalSpeechModel(modelId, {
155	      provider: `fal.speech`,
156	      url: ({ path }) => path,
157	      headers: getHeaders,
158	      fetch: options.fetch,
159	    });
160	
161	  const createTranscriptionModel = (modelId: FalTranscriptionModelId) =>
162	    new FalTranscriptionModel(modelId, {
163	      provider: `fal.transcription`,
164	      url: ({ path }) => path,
165	      headers: getHeaders,
166	      fetch: options.fetch,
167	    });
168	
169	  const createVideoModel = (modelId: FalVideoModelId) =>
170	    new FalVideoModel(modelId, {
171	      provider: 'fal.video',
172	      url: ({ path }) => path,
173	      headers: getHeaders,
174	      fetch: options.fetch,
175	    });
176	
177	  const embeddingModel = (modelId: string) => {
178	    throw new NoSuchModelError({
179	      modelId,
180	      modelType: 'embeddingModel',
181	    });
182	  };
183	
184	  return {
185	    specificationVersion: 'v3' as const,
186	    imageModel: createImageModel,
187	    image: createImageModel,
188	    languageModel: (modelId: string) => {
189	      throw new NoSuchModelError({
190	        modelId,
191	        modelType: 'languageModel',
192	      });
193	    },
194	    speech: createSpeechModel,
195	    embeddingModel,
196	    textEmbeddingModel: embeddingModel,
197	    transcription: createTranscriptionModel,
198	    video: createVideoModel,
199	    videoModel: createVideoModel,
200	  };
201	}
202	
203	/**
204	 * Default fal.ai provider instance.
205	 */
206	export const fal = createFal();
