### 3. **<provider>-provider.ts** - Factory & Provider Interface

**Structure (from FAL):**

```typescript
export interface YourProviderSettings {
  apiKey?: string;           // Or apiToken, depends on provider
  baseURL?: string;          // Defaults to provider's API URL
  headers?: Record<string, string>;
  fetch?: FetchFunction;     // For custom fetch/middleware
}

export interface YourProvider extends ProviderV3 {
  image(modelId: YourImageModelId): ImageModelV3;
  imageModel(modelId: YourImageModelId): ImageModelV3;
  textEmbeddingModel(modelId: string): never; // Stub - image-only
}

export function createYourProvider(
  options: YourProviderSettings = {}
): YourProvider {
  // 1. Setup baseURL with withoutTrailingSlash
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  // 2. Create getHeaders function
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'YOUR_API_KEY',
          description: 'YourProvider',
        })}`,
        ...options.headers,
      },
      `ai-sdk/yourprovider/${VERSION}`,
    );

  // 3. Create model factory
  const createImageModel = (modelId: YourImageModelId) =>
    new YourImageModel(modelId, {
      provider: 'yourprovider.image',
      baseURL,
      headers: getHeaders,  // Note: getHeaders(), not getHeaders for Replicate
      fetch: options.fetch,
    });

  // 4. Return provider object
  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
    textEmbeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
  };
}

export const yourProvider = createYourProvider();
```

**Important notes:**
- FAL and Luma use `getHeaders` function (called on each request)
- Replicate uses `getHeaders()` - called once during initialization
- Always use `loadApiKey` from `@ai-sdk/provider-utils` for environment variable handling
- Must implement `ProviderV3` interface with `specificationVersion: 'v3'`
- Stub out unsupported model types with `NoSuchModelError`

