        safetyTolerance: z
          .enum(['1', '2', '3', '4', '5', '6'])
          .or(z.number().min(1).max(6))
          .nullish(),
        useMultipleImages: z.boolean().nullish(),

        // Deprecated snake_case versions
        image_url: z.string().nullish(),
        mask_url: z.string().nullish(),
        // ... etc
      })
      .passthrough()
      .transform(data => {
        // Transform logic to convert snake_case to camelCase
        // and track deprecated keys for warnings
      }),
  ),
);

export type FalImageModelOptions = InferSchema<typeof falImageModelOptionsSchema>;
```

### 4.6 src/fal-image-settings.ts (Model IDs & Sizes)

```typescript
export type FalImageModelId =
  | 'fal-ai/flux-general'
  | 'fal-ai/flux-pro/v1.1'
  | 'fal-ai/qwen-image'
  | 'fal-ai/bria/text-to-image/base'
  | (string & {}); // Allow custom model IDs

