        details: expect.stringContaining('files'),
      });
    });

    it('should warn when mask is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: { type: 'url', url: 'https://example.com/mask.png', mediaType: 'image/png' },
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'mask',
        details: expect.stringContaining('mask'),
      });
    });

    it('should include no warnings for fully supported options', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '128x128',
        aspectRatio: undefined,
